priority_scoring.scoring_function:
function scoreQuestion(dq, session) {
    // Gate check: skip if already asked or skipped
    if (session.dq_status[dq.item_id] !== 'unasked') return -1;

    let score = 0;

    // 1. MEETING STAGE MATCH (0-10)
    if (dq.stage_relevance.includes(session.current_stage_id)) {
        score += 10;
    } else if (dq.meeting_relevance.includes(session.current_meeting_id)) {
        score += 3;
    }
    // If score is 0 after stage match, exclude entirely
    if (score === 0) return -1;

    // 2. SIGNAL CLUSTER MATCH (0-10)
    const activeCluster = session.active_cluster;
    if (activeCluster) {
        const bridgedSignals = dq.conversation_signals
            .flatMap(sig => signal_bridge[sig] || []);
        const clusterSignals = activeCluster.confidence_signals;
        const overlap = bridgedSignals.filter(s => clusterSignals.includes(s));
        if (overlap.length >= 2) score += 10;
        else if (overlap.length === 1) score += 6;
    } else {
        // No cluster active — check raw signal presence in transcript
        const transcriptSignals = session.detected_signals;
        const overlap = dq.conversation_signals
            .filter(s => transcriptSignals.includes(s));
        if (overlap.length >= 1) score += 3;
    }

    // 3. PRINCIPLE MATCH (0-10)
    if (activeCluster && activeCluster.decision_rules) {
        const preferred = activeCluster.decision_rules.preferred_principle;
        if (dq.principle_tags.includes(preferred)) {
            score += 10;
        } else {
            // Check for adjacent principle alignment
            const stageShift = getCurrentStage().belief_shift_target;
            // Award 5 if any principle maps to the stage's belief shift
            score += 5;
        }
    }

    // 4. ADVANCING VS CONFIRMING FIT (0-10)
    if (activeCluster && activeCluster.decision_rules) {
        const preferred = activeCluster.decision_rules.preferred_question_type;
        if (dq.question_type === preferred) {
            score += 10;
        } else {
            score += 2;
        }
    } else {
        // No cluster — use stage heuristic
        const pctAsked = getPercentAsked(session);
        if (dq.question_type === 'advancing' && pctAsked < 0.6) score += 8;
        else if (dq.question_type === 'confirming' && pctAsked > 0.8) score += 8;
        else score += 4;
    }

    // 5. MEDDPICC RELEVANCE (0-10)
    const coverage = session.meddpicc_coverage;
    let meddpiccBoost = 1;
    for (const tag of dq.methodology_tags) {
        const element = tag.replace('MEDDPICC-', '');
        if (!coverage[element] || coverage[element] === 0) {
            meddpiccBoost = 10; break;
        } else if (coverage[element] === 1) {
            meddpiccBoost = Math.max(meddpiccBoost, 5);
        } else {
            meddpiccBoost = Math.max(meddpiccBoost, 2);
        }
    }
    score += meddpiccBoost;

    return score;  // Range: 14-50 (minimum viable = stage match + something)
}

speaker_detection.pseudocode:
function classifySegment(segment, session) {
    const text = segment.text.trim().toLowerCase();
    const words = text.split(/\s+/);

    // Safety: too short to classify
    if (words.length < 4) {
        // Check if it's a known acknowledgment
        const ackPhrases = speaker_detection.consecutive_turn_override
            .override_conditions[0].phrases;
        const isAck = ackPhrases.some(p => text === p || text === p + '.');
        if (isAck) {
            // KEEP current speaker — do not flip, do not trigger
            session.message_index++;
            return { role: session.current_speaker, action: 'SKIP' };
        }
        return { role: 'uncertain', action: 'HOLD' };
    }

    // First message rule
    if (session.message_index === 0) {
        const greetings = speaker_detection.first_message_rule.greeting_phrases;
        const isGreetingOnly = words.every(w =>
            greetings.some(g => g.includes(w) || w.includes(g))
        );
        session.current_speaker = isGreetingOnly ? 'client' : 'sales_rep';
        session.message_index++;
        return { role: session.current_speaker, action: 'EVALUATE' };
    }

    // Check for handoff signals (these FORCE a flip)
    const prevText = session.previous_segment_text || '';
    const hasHandoff =
        prevText.endsWith('?') ||
        /what do you think|does that make sense|over to you/.test(prevText) ||
        /^(well|honestly|that's a good question|so for us)/.test(text);

    if (hasHandoff && segment.pause_before_ms >= 800) {
        // Handoff detected — flip speaker
        session.current_speaker =
            session.current_speaker === 'sales_rep' ? 'client' : 'sales_rep';
        session.previous_segment_text = text;
        session.message_index++;
        return { role: session.current_speaker, action: 'EVALUATE' };
    }

    // Check consecutive-turn override conditions
    const continuationStarters = [
        'and ', 'so ', 'but ', 'also ', 'plus ', 'because ',
        'which ', 'that said', 'i mean', 'well actually',
        'let me rephrase', 'the second', 'another ', 'on top of'
    ];
    const isContinuation = continuationStarters.some(s => text.startsWith(s));

    const isShortPause = segment.pause_before_ms >= 800 &&
                         segment.pause_before_ms < 1500;

    // Apply override: KEEP current speaker if any override condition is met
    if (segment.pause_before_ms >= 1500) {
        if (isContinuation) {
            // Topic continuation — keep current speaker
        } else {
            // No override — flip speaker
            session.current_speaker =
                session.current_speaker === 'sales_rep' ? 'client' : 'sales_rep';
        }
    }
    // Pauses under 1500ms: always keep current speaker (mid-thought or override)

    session.previous_segment_text = text;
    session.message_index++;

    const action = session.current_speaker === 'client' ? 'EVALUATE' : 'SKIP';
    return { role: session.current_speaker, action };
}

function processTriggers(segment, session) {
    const result = classifySegment(segment, session);

    if (result.action === 'EVALUATE') {
        runTriggerDetection(segment.text);
        runClusterMatching(segment.text);
        runPriorityScoring(session);
    }
    // SKIP and HOLD: do nothing
}

session_script_system.pseudocode:
// SESSION START
function startMeetingSession(meetingType, selectedScriptId) {
    const canonical = brain.session_script_system.canonical_scripts.registry
        .find(s => s.script_id === selectedScriptId);

    if (!canonical) {
        // Default to first script for this meeting type
        canonical = brain.session_script_system.canonical_scripts.registry
            .find(s => s.meeting === meetingType);
    }

    // Get full text from brain
    const fullText = getOpeningStatementText(canonical.source_item_id);

    // Create session copy
    session.active_script = {
        session_id: generateSessionId(),
        source_script_id: canonical.script_id,
        source_item_id: canonical.source_item_id,
        temporary_override: true,
        editable: true,
        created_at: new Date().toISOString(),
        last_edited_at: null,
        edit_count: 0,
        content: fullText  // Copy of canonical — editable
    };
}

// EDITING
function editSessionScript(newContent) {
    session.active_script.content = newContent;
    session.active_script.edit_count++;
    session.active_script.last_edited_at = new Date().toISOString();
    // Canonical script is NEVER touched
}

// RESET
function resetToDefault() {
    const canonical = getOpeningStatementText(
        session.active_script.source_item_id
    );
    session.active_script.content = canonical;
    session.active_script.edit_count = 0;
    session.active_script.last_edited_at = null;
}

// SESSION END
function endMeetingSession() {
    session.active_script = null;  // Deleted — no persistence
}

// DISPLAY
function getDisplayScript() {
    if (session.active_script) {
        return session.active_script.content;  // Session version
    }
    return null;  // No session active
}

response_chaining.pseudocode:
function chainResponse(primaryCard, session) {
    const move = primaryCard.move_type;

    // Only chain non-question moves
    if (['advancing_question', 'confirming_question', 'roi_prompt', 'next_step_lock'].includes(move)) {
        return { primary: primaryCard, chain: null };
    }

    const cluster = session.active_cluster;
    if (!cluster) {
        return { primary: primaryCard, chain: null };
    }

    // Step 1: Check pre-computed chain map
    const chainMap = response_chaining.cluster_chain_map.chains[cluster.pattern_id];
    if (chainMap) {
        for (const dqId of chainMap.primary_chain_dqs) {
            if (session.dq_status[dqId] === 'unasked' && isInCurrentStage(dqId, session)) {
                return { primary: primaryCard, chain: getDQ(dqId) };
            }
        }
    }

    // Step 2-3: Signal match → Principle match (via scoring engine)
    const candidates = scoreAllUnaskedAdvancing(session)
        .filter(dq => dq.stage === session.current_stage);

    if (candidates.length > 0) {
        return { primary: primaryCard, chain: candidates[0] };
    }

    // Step 5: No chain available
    return { primary: primaryCard, chain: null };
}
